#!/usr/bin/env node
import {
  formatSharedSyncResult,
  syncSharedKnowledge,
} from "../dist/shared-sync.js";
import { COMMAND_SPECS } from "../dist/bot-setup.js";

let pass = 0;
let fail = 0;

function assert(name, condition, detail = "") {
  if (condition) {
    pass++;
    console.log(`[PASS] ${name}`);
  } else {
    fail++;
    console.log(`[FAIL] ${name}${detail ? ` — ${detail}` : ""}`);
  }
}

function makeRunner({ status = "", failFirstPush = false, pulledFiles = [] } = {}) {
  const calls = [];
  let pushCount = 0;
  let revParseCount = 0;
  const runGit = async (args, cwd) => {
    calls.push(args.join(" "));
    if (cwd !== "/shared") throw new Error(`unexpected cwd: ${cwd}`);
    const cmd = args.join(" ");
    if (cmd === "status --porcelain") return { stdout: status, stderr: "" };
    if (cmd === "config --get user.name") throw new Error("missing user.name");
    if (cmd === "config --get user.email") throw new Error("missing user.email");
    if (cmd.startsWith("config --local user.name ")) return { stdout: "", stderr: "" };
    if (cmd.startsWith("config --local user.email ")) return { stdout: "", stderr: "" };
    if (cmd === "add -A") return { stdout: "", stderr: "" };
    if (cmd.startsWith("commit -m ")) return { stdout: "[main abc] sync", stderr: "" };
    if (cmd === "pull --rebase") return { stdout: "Already up to date.", stderr: "" };
    if (cmd === "rev-parse HEAD") {
      revParseCount++;
      return { stdout: pulledFiles.length > 0 && revParseCount === 2 ? "head-after" : "head-before", stderr: "" };
    }

