const ATTEMPT_BRANCH = "sync-attempt";

function git(args, { capture = true } = {}) {
  const res = spawnSync("git", args, {
    encoding: "utf8",
    stdio: capture ? ["ignore", "pipe", "pipe"] : "inherit",
  });
  return {
    code: res.status ?? 1,
    stdout: (res.stdout ?? "").trim(),
    stderr: (res.stderr ?? "").trim(),
  };
}

function die(code, msg) {
  console.error(`\n✗ ${msg}`);
  process.exit(code);
}

function step(msg) {
  console.log(`\n▸ ${msg}`);
}

// ── 0. 前置檢查 ───────────────────────────────────────────────────────────────
step("檢查前置條件");

if (git(["rev-parse", "--git-dir"]).code !== 0) {
  die(3, "不在 git repo 內。");
}

// 進行中的 merge?
if (git(["rev-parse", "-q", "--verify", "MERGE_HEAD"]).code === 0) {
  die(3, "偵測到進行中的 merge。先處理完(git merge --abort 或解完 commit)再跑。");
}

// 工作目錄乾淨?
const dirty = git(["status", "--porcelain"]).stdout;
if (dirty) {
  console.error(dirty);
  die(3, "工作目錄有未提交變更。先 commit 或 stash 再同步。");
}

// upstream remote 存在?
if (git(["remote", "get-url", UPSTREAM]).code !== 0) {
  die(3, `找不到 remote「${UPSTREAM}」。先 git remote add ${UPSTREAM} <原專案網址>。`);
}

const currentBranch = git(["rev-parse", "--abbrev-ref", "HEAD"]).stdout;
console.log(`  目前分支:${currentBranch}`);

// ── 1. fetch ─────────────────────────────────────────────────────────────────
step(`fetch ${UPSTREAM}`);
const fetched = git(["fetch", UPSTREAM], { capture: false });
if (fetched.code !== 0) die(1, "fetch 失敗(看上方錯誤)。");

// ── 2. 落後幾個 commit ────────────────────────────────────────────────────────
const behind = Number(
  git(["rev-list", "--count", `${BASE_BRANCH}..${UPSTREAM_BRANCH}`]).stdout || "0",
);
const ahead = Number(
  git(["rev-list", "--count", `${UPSTREAM_BRANCH}..${BASE_BRANCH}`]).stdout || "0",
);
console.log(`  ${BASE_BRANCH} 落後 upstream ${behind} 個 commit、領先 ${ahead} 個。`);

if (behind === 0) {
  console.log("\n✓ 已是最新,無需同步。");
  process.exit(0);
}

// ── 3. 開拋棄式分支 ───────────────────────────────────────────────────────────
step(`從 ${BASE_BRANCH} 建立 ${ATTEMPT_BRANCH}`);
const sw = git(["switch", "-C", ATTEMPT_BRANCH, BASE_BRANCH]);
if (sw.code !== 0) die(1, `建立 ${ATTEMPT_BRANCH} 失敗:${sw.stderr}`);

// ── 4. 嘗試 merge ─────────────────────────────────────────────────────────────
step(`merge ${UPSTREAM_BRANCH}`);
const merged = git(["merge", "--no-edit", UPSTREAM_BRANCH], { capture: false });

if (merged.code !== 0) {
  const conflicts = git(["diff", "--name-only", "--diff-filter=U"]).stdout;
  console.error("\n⚠ 出現衝突,需要判斷。衝突檔案:");
  console.error(conflicts ? conflicts.split("\n").map((f) => `    - ${f}`).join("\n") : "    (無法列出)");
  console.error(
    `\n  狀態:停在分支「${ATTEMPT_BRANCH}」、merge 進行中。${BASE_BRANCH} 未受影響。\n` +
      "  解法:逐檔解衝突 → git add → git commit → 再跑 build。\n" +
      `  放棄:git merge --abort && git switch ${BASE_BRANCH} && git branch -D ${ATTEMPT_BRANCH}`,
  );
  process.exit(10);
}

// ── 5. build ─────────────────────────────────────────────────────────────────
step("npm run build");
const built = spawnSync(process.platform === "win32" ? "npm.cmd" : "npm", ["run", "build"], {
  stdio: "inherit",
});
if ((built.status ?? 1) !== 0) {
  console.error(
    `\n✗ build 失敗。狀態:合併已完成於「${ATTEMPT_BRANCH}」,但編譯不過。\n` +
      "  修正編譯錯誤後重跑 build;或放棄:" +
      `git switch ${BASE_BRANCH} && git branch -D ${ATTEMPT_BRANCH}`,
  );
  process.exit(11);
}

// ── 6. 成功 ───────────────────────────────────────────────────────────────────
console.log(
  `\n✓ 合併乾淨且 build 通過(分支「${ATTEMPT_BRANCH}」)。${BASE_BRANCH} 尚未變動、尚未 push。\n\n` +
    "  建議先實測功能。確認 OK 後發佈:\n" +
    `    git switch ${BASE_BRANCH}\n` +
    `    git merge --ff-only ${ATTEMPT_BRANCH}\n` +
    "    git push origin main\n" +
    `    git branch -d ${ATTEMPT_BRANCH}\n`,
);
process.exit(0);

