      `git switch ${BASE_BRANCH} && git branch -D ${ATTEMPT_BRANCH}`,
  );
  process.exit(11);
}

// ── 5b. 型別檢查(不 emit,避免與執行中的 bridge 搶 dist/ 鎖)─────────────────
step("npx tsc --noEmit(型別檢查)");
const typecheck = spawnSync(process.platform === "win32" ? "npx.cmd" : "npx", ["tsc", "--noEmit"], {
  stdio: "inherit",
});
if ((typecheck.status ?? 1) !== 0) {
  console.error(
    `\n✗ 型別檢查失敗。狀態:合併已完成於「${ATTEMPT_BRANCH}」,但編譯不過。\n` +
      "  修正編譯錯誤後重跑;或放棄:" +
      `git switch ${BASE_BRANCH} && git branch -D ${ATTEMPT_BRANCH}`,
  );
  process.exit(11);
}

// ── 6. 成功 ───────────────────────────────────────────────────────────────────
console.log(
  `\n✓ 合併乾淨且型別檢查通過(分支「${ATTEMPT_BRANCH}」)。${BASE_BRANCH} 尚未變動、尚未 push。\n\n` +
    "  建議先實測功能。確認 OK 後發佈:\n" +
    `    git switch ${BASE_BRANCH}\n` +
    `    git merge --ff-only ${ATTEMPT_BRANCH}\n` +
    "    git push origin main\n" +
    `    git branch -d ${ATTEMPT_BRANCH}\n`,
);
process.exit(0);

